const now = Date.now();
const running = flow.get('agg_only_isProcessing') || false;
const lastStart = flow.get('agg_only_lastStart') || 0;
const maxRuntimeMs = 10 * 60 * 1000;

if (running && (now - lastStart) < maxRuntimeMs) {
    node.status({ fill: 'yellow', shape: 'ring', text: 'Skipped: still processing' });
    return null;
}

flow.set('agg_only_isProcessing', true);
flow.set('agg_only_lastStart', now);
flow.set('agg_only_stats', {
    startedAt: now,
    seen: 0,
    mapped: 0,
    skipped: 0,
    dataAllOps: 0,
    alarmOps: 0,
    dataAllBatches: 0,
    alarmBatches: 0,
    errors: 0,
    lastMsgAt: now
});
flow.set('agg_only_data_all_buffer', []);
flow.set('agg_only_alarm_buffer', []);

node.status({ fill: 'blue', shape: 'dot', text: 'Running aggregate only...' });
return msg;

msg.collection = 'endpoints';
msg.operation = 'find';
msg.payload = { _id: { $type: 'objectId' } };

// Projection: do not load username/password.
msg.projection = {
    _id: 0,
    id: 1,
    mac_address: 1,
    xweb_name: 1,
    external_ip: 1,
    url: 1,
    owner: 1,
    branch_id: 1
};

return msg;

const limitTime = 900000; // 15 minutes
const OFFLINE_THRESHOLD = 2;

function stat(name) {
    const s = flow.get('agg_only_stats') || {};
    s[name] = (s[name] || 0) + 1;
    s.lastMsgAt = Date.now();
    flow.set('agg_only_stats', s);
}
function normalizeTimestamp(ts) {
    let t = Number(ts);
    if (!t) return 0;
    if (t < 1e12) t *= 1000;
    return t;
}
function isOlderThanLimit(ts) {
    if (!ts) return true;
    return Date.now() - ts > limitTime;
}
function decodeText(str = '') {
    if (typeof str !== 'string') return '';
    try {
        return decodeURIComponent(str.replace(/%(?![0-9A-Fa-f]{2})/g, '%25'));
    } catch (e) {
        return str;
    }
}

const conf = msg.payload || {};
const mac = String(conf.mac_address || '').trim().toUpperCase();
stat('seen');

if (!mac) {
    stat('skipped');
    return null;
}

const setup = global.get('xgetsetup')?.[mac]?.setup_data;
const streamObj = global.get('xstream')?.[mac]?.stream_data;
const sys = global.get('xsysinfo')?.[mac]?.sysinfo_data;
let communications = global.get('CheckCommunications') || {};
const now = Date.now();

const output = {
    name: decodeText(sys?.info?.name || '') || conf.xweb_name || mac,
    mac_address: mac,
    on: streamObj?.stream?.acq || 0,
    branch_id: conf.branch_id || '',
    owner: conf.owner || '',
    url: conf.url || conf.external_ip || '',
    external_ip: conf.external_ip || conf.url || '',
    devices: []
};

if (!communications[mac]) {
    communications[mac] = { status: false, offline_streak: 0, offline_count: 0 };
}

const ts = normalizeTimestamp(streamObj?.ts);
const isOffline = isOlderThanLimit(ts);

if (isOffline) {
    communications[mac].offline_streak = Math.min((communications[mac].offline_streak || 0) + 1, OFFLINE_THRESHOLD);
} else {
    communications[mac].offline_streak = 0;
}

if (communications[mac].offline_streak === OFFLINE_THRESHOLD && communications[mac].status === false) {
    communications[mac] = {
        ...communications[mac],
        store_name: conf.xweb_name,
        mac_address: mac,
        device_name: conf.xweb_name,
        alarm_name: 'Offline',
        text: 'Offline',
        status: true,
        acknow: false,
        dateStart: now,
        offline_count: 0,
        offline_timestamp: null
    };
}

if (communications[mac].offline_streak === 0 && communications[mac].status === true) {
    communications[mac].status = false;
}

global.set('CheckCommunications', communications);

const cate = {};
const ctgs = setup?.setup?.ctgs;
if (Array.isArray(ctgs)) {
    for (const category of ctgs) {
        const cateName = decodeText(category?.term || '');
        for (const devId of (category?.devs || [])) {
            cate[devId] = cateName;
        }
    }
}

const streamData = streamObj?.stream?.data;
const devicesSetup = setup?.devices || {};

if (streamData && typeof streamData === 'object') {
    const deviceIds = Object.keys(streamData);

    for (const deviceId of deviceIds) {
        const device = devicesSetup?.[deviceId];
        if (!device || !device.vrs) continue;

        const devGen = device?.gen || {};
        const groups = {
            analogInput: [],
            deviceStatus: [],
            alarm: [],
            digitalinput: [],
            outputStatus: [],
            chartDef: []
        };

        const pointIds = Object.keys(device.vrs);
        for (const pointId of pointIds) {
            const point = device.vrs[pointId];
            if (!point || point.vfr !== 1) continue;

            const lng = device?.lng?.vrs?.[pointId];
            if (!lng) continue;

            let group = null;
            switch (point.vgrp) {
                case 0: group = 'analogInput'; break;
                case 1: group = 'deviceStatus'; break;
                case 2: group = 'alarm'; break;
                case 3: group = 'digitalinput'; break;
                case 4: group = 'outputStatus'; break;
                default: continue;
            }

            const name = decodeText(lng.uvun || lng.vun || '');
            const value = streamData?.[deviceId]?.[pointId] ?? 0;
            const unit = point.vudm;
            const item = { pointId, name, value, unit };

            groups[group].push(item);

            if (point.chartDef?.en === true) {
                groups.chartDef.push({ pointId, name, value, index: pointId, unit });
            }
        }
        output.devices.push({
            name: decodeText(devGen.name || ''),
            adr: devGen.addr2,
            cate: cate[deviceId] || 'Others',
            uid: deviceId,
            lanid: devGen.addr1,
            model: devGen.model,
            dbpath: devGen.dbpath,
            analogInput: groups.analogInput,
            deviceStatus: groups.deviceStatus,
            alarm: groups.alarm,
            digitalinput: groups.digitalinput,
            outputStatus: groups.outputStatus,
            chartDef: groups.chartDef
        });
    }
}

msg.conf = {
    mac_address: mac,
    xweb_name: conf.xweb_name || '',
    owner: conf.owner || '',
    branch_id: conf.branch_id || '',
    url: conf.url || conf.external_ip || '',
    external_ip: conf.external_ip || conf.url || ''
};
msg.mac_address = mac;
msg.payload = output;
stat('mapped');
return msg;

const data = msg.payload || {};
const mac = msg.mac_address || data.mac_address;

function safeDecode(text = '') {
    try {
        return decodeURIComponent(String(text).replace(/%(?![0-9A-Fa-f]{2})/g, '%25'));
    } catch (e) {
        return text;
    }
}

const alarmDevices = global.get('xalarms')?.[mac]?.devices || {};

for (const dev of data.devices || []) {
    const alarms = alarmDevices?.[dev.uid]?.alarms || {};
    const activeAlarms = [];

    for (const pointId in alarms) {
        const a = alarms[pointId];
        if (!a?.en) continue;

        activeAlarms.push({
            pointId,
            name: safeDecode(a.name),
            value: a.value,
            unit: a.unit
        });
    }

    if (activeAlarms.length) {
        dev.alarm = activeAlarms;
    }
}

msg.payload = data;
return msg;

const data = msg.payload || {};
const conf = msg.conf || {};
const mac = msg.mac_address || data.mac_address || conf.mac_address;
const date_now = Date.now();

const xalarms = global.get('xalarms') || {};
const xstream = global.get('xstream') || {};
const chk_offline = global.get('Offline') || {};
const chk_commu = global.get('CheckCommunications') || {};
let chk_watch = global.get('chk_watch') || {};
const active_alarms_global = global.get('Active_Alarms') || {};

function safeDecode(t) {
    if (t === undefined || t === null) return '';
    try {
        return decodeURIComponent(String(t).replace(/%(?![0-9A-Fa-f]{2})/g, '%25'));
    } catch (e) {
        return String(t);
    }
}

function sanitizeKeys(obj) {
    if (Array.isArray(obj)) return obj.map(sanitizeKeys);
    if (obj && typeof obj === 'object') {
        const clean = {};
        for (const k in obj) {
            if (k.startsWith('$') || k.includes('.')) continue;
            clean[k] = sanitizeKeys(obj[k]);
        }
        return clean;
    }
    return obj;
}

function counterAlarmFromXalarms(devices = {}) {
    let active = 0;
    const total = Object.keys(devices).length;

    for (const did in devices) {
        const alarms = devices[did]?.alarms || {};
        for (const pid in alarms) {
            const al = alarms[pid];
            if (al?.en && al?.value) active++;
        }
    }

    return { active, total };
}

function counterAlarmFromDevices(devices = []) {
    let active = 0;
    const total = Array.isArray(devices) ? devices.length : 0;

    for (const d of devices || []) {
        for (const al of d.alarm || []) {
            if (al.value > 0) {
                active++;
                break;
            }
        }
    }

    return { active, total, alarm: active > 0 ? 1 : 0 };
}

function buildSensorDevices() {
    const devices = {};

    for (const d of data.devices || []) {
        const realtime = [];
        const deviceStatus = [];
        const analogInput = [];
        const alarm = [];

        for (const c of d.chartDef || []) {
            realtime.push({ name: c.name, value: c.value, unit: c.unit });
        }
        for (const s of d.deviceStatus || []) {
            deviceStatus.push({ point_id: s.pointId, name: s.name, value: s.value });
        }
        for (const a of d.analogInput || []) {
            analogInput.push({ point_id: a.pointId, name: a.name, value: a.value, unit: a.unit });
        }
        for (const al of d.alarm || []) {
            if (al.value) {
                alarm.push({ point_id: al.pointId, name: al.name, value: al.value });
            }
        }

        devices[d.uid] = {
            name: safeDecode(d.name),
            adr: d.adr,
            deviceid: d.uid,
            model: d.model,
            realTime: realtime,
            deviceStatus,
            analogInput,
            alarm
        };
    }
    return devices;
}

function buildActiveAlarms(sensorDevices) {
    const arr = [];
    const xdevs = xalarms[mac]?.devices || {};

    for (const did in xdevs) {
        const alarms = xdevs[did]?.alarms || {};

        for (const pid in alarms) {
            const al = alarms[pid];
            if (!al?.en || !al?.value) continue;

            const idx = `${mac}_${did}_${pid}`;

            if (!chk_watch[idx]) {
                chk_watch[idx] = {
                    note: '',
                    acknow: 0,
                    count: 0,
                    acknow_count: 0,
                    timestamp: date_now
                };
            }

            const ts = chk_watch[idx].count > 0
                ? chk_watch[idx].timestamp
                : active_alarms_global[idx]?.dateStart ?? date_now;

            arr.push({
                xweb_name: safeDecode(data.name),
                mac_address: data.mac_address || mac,
                owner: conf.owner || data.owner || '',
                device_name: safeDecode(sensorDevices?.[did]?.name),
                device_adr: sensorDevices?.[did]?.adr ?? '-',
                device_id: did,
                name: safeDecode(al.name),
                point_id: pid,
                status: al.value > 0 ? 'Active' : 'Normal',
                note: chk_watch[idx].note ?? '',
                acknow: chk_watch[idx]?.acknow,
                chk_watch: chk_watch[idx]?.count,
                timestamp: ts,
                startTime: active_alarms_global[idx]?.dateStart
            });
        }
    }

    return arr;
}

const offlineObj = chk_offline[mac];
const isOffline = !!offlineObj;
const sensorDevices = isOffline ? {} : buildSensorDevices();

const dataAllDoc = isOffline ? {
    mac,
    _attr: {
        site_name: conf.xweb_name || data.name || '',
        status_acq: 0,
        mac,
        url: conf.url || conf.external_ip || data.url || '',
        communication: 'Offline',
        owner: conf.owner || data.owner || '',
        branch_id: conf.branch_id || data.branch_id || '',
        lastest_updated: xstream[mac]?.stream_data?.ts ?? date_now
    },
    _status: { active: 0, total: 0 },
    _active_alarms: [],
    _devices: {}
} : {
    mac,
    _attr: {
        site_name: data.name || conf.xweb_name || '',
        status_acq: data.on ?? 0,
        mac,
        url: conf.url || conf.external_ip || data.url || '',
        communication: 'Online',
        owner: conf.owner || data.owner || '',
        branch_id: conf.branch_id || data.branch_id || '',
        lastest_updated: xstream[mac]?.stream_data?.ts
    },
    _status: counterAlarmFromXalarms(xalarms[mac]?.devices || {}),
    _active_alarms: buildActiveAlarms(sensorDevices),
    _devices: sensorDevices
};

const commu = chk_commu[mac] || {};
let chk_sum = { count: 0, acknow: 0, acknow_count: 0 };

if (!isOffline) {
    for (const key in chk_watch) {
        if (key.startsWith(mac)) {
            const v = chk_watch[key] || {};
            chk_sum.count += v.count || 0;
            chk_sum.acknow += v.acknow || 0;
            chk_sum.acknow_count += v.acknow_count || 0;
        }
    }
}

const alarmDoc = isOffline ? {
    mac,
    store_name: conf.xweb_name || data.name || '',
    url: conf.external_ip || conf.url || data.external_ip || data.url || '',
    communication: 'Offline',
    owner: conf.owner || data.owner || '',
    note: offlineObj?.acknow ? offlineObj?.text || 'Acknowledge' : '',
    date_offline: offlineObj?.dateStart || date_now,
    acknow_offline: offlineObj?.acknow || false,
    alarm: { active: 0, total: 0 },
    chk_watch: 0,
    acknow: 0,
    acknow_count: 0,
    offline_count: commu.offline_count || 0,
    offline_timestamp: commu.offline_timestamp || date_now
} : {
    mac,
    store_name: data.name || conf.xweb_name || '',
    url: conf.external_ip || conf.url || data.external_ip || data.url || '',
    communication: 'Online',
    owner: conf.owner || data.owner || '',
    note: '',
    alarm: counterAlarmFromDevices(data.devices || []),
    chk_watch: chk_sum.count,
    acknow: chk_sum.acknow,
    acknow_count: chk_sum.acknow_count,
    offline_count: commu.offline_count || 0,
    offline_timestamp: commu.offline_timestamp || date_now
};

global.set('chk_watch', chk_watch);

msg.payload = {
    mac,
    dataAll: {
        updateOne: {
            filter: { mac },
            update: {
                $set: sanitizeKeys(dataAllDoc),
                $currentDate: { lastModified: true }
            },
            upsert: true
        }
    },
    alarmAggregate: {
        updateOne: {
            filter: { mac },
            update: {
                $set: sanitizeKeys(alarmDoc),
                $currentDate: { lastModified: true }
            },
            upsert: true
        }
    }
};

return msg;

const BATCH_SIZE = 100;
const item = msg.payload || {};

function stat(name, n = 1) {
    const s = flow.get("agg_only_stats") || {};
    s[name] = (s[name] || 0) + n;
    s.lastMsgAt = Date.now();
    flow.set("agg_only_stats", s);
}

let dataAllBuffer = flow.get("agg_only_data_all_buffer") || [];
let alarmBuffer = flow.get("agg_only_alarm_buffer") || [];

if (item.dataAll) {
    dataAllBuffer.push(item.dataAll);
    stat("dataAllOps");
}

if (item.alarmAggregate) {
    alarmBuffer.push(item.alarmAggregate);
    stat("alarmOps");
}

const messages = [];

if (dataAllBuffer.length >= BATCH_SIZE) {
    messages.push({
        collection: "data_all",
        operation: "bulkWrite",
        payload: dataAllBuffer.splice(0, BATCH_SIZE),
        options: { ordered: false },
        topic: "bulkWrite:data_all"
    });
    stat("dataAllBatches");
}

if (alarmBuffer.length >= BATCH_SIZE) {
    messages.push({
        collection: "alarms_aggregate",
        operation: "bulkWrite",
        payload: alarmBuffer.splice(0, BATCH_SIZE),
        options: { ordered: false },
        topic: "bulkWrite:alarms_aggregate"
    });
    stat("alarmBatches");
}

flow.set("agg_only_data_all_buffer", dataAllBuffer);
flow.set("agg_only_alarm_buffer", alarmBuffer);

// ส่งออกหลาย msg ใน output เดียว
if (messages.length > 0) {
    return [messages];
}

return null;

const running = flow.get('agg_only_isProcessing') || false;
if (!running) return [null, null];

const stats = flow.get('agg_only_stats') || {};
const now = Date.now();
const idleMs = 15000;
const maxRuntimeMs = 10 * 60 * 1000;
const lastMsgAt = stats.lastMsgAt || stats.startedAt || now;
const startedAt = stats.startedAt || now;

node.status({
    fill: 'blue',
    shape: 'ring',
    text: `seen:${stats.seen || 0} mapped:${stats.mapped || 0} data:${stats.dataAllOps || 0}`
});

if ((now - lastMsgAt) <= idleMs && (now - startedAt) <= maxRuntimeMs) {
    return [null, null];
}

const dataAllBuffer = flow.get('agg_only_data_all_buffer') || [];
const alarmBuffer = flow.get('agg_only_alarm_buffer') || [];
const out = [];

if (dataAllBuffer.length > 0) {
    out.push({
        collection: 'data_all',
        operation: 'bulkWrite',
        payload: dataAllBuffer,
        options: { ordered: false },
        topic: 'bulkWrite:data_all:final'
    });
    stats.dataAllBatches = (stats.dataAllBatches || 0) + 1;
}

if (alarmBuffer.length > 0) {
    out.push({
        collection: 'alarms_aggregate',
        operation: 'bulkWrite',
        payload: alarmBuffer,
        options: { ordered: false },
        topic: 'bulkWrite:alarms_aggregate:final'
    });
    stats.alarmBatches = (stats.alarmBatches || 0) + 1;
}

flow.set('agg_only_data_all_buffer', []);
flow.set('agg_only_alarm_buffer', []);
flow.set('agg_only_isProcessing', false);

stats.runtimeMs = now - startedAt;
flow.set('agg_only_stats', stats);

const summary = {
    payload: {
        ok: true,
        message: 'Aggregate only pipeline idle flushed/unlocked',
        finalBatches: out.length,
        stats
    }
};

node.status({ fill: 'green', shape: 'dot', text: `Done seen:${stats.seen || 0}, final:${out.length}` });
return [out.length ? out : null, summary];

const s = flow.get('agg_only_stats') || {};
s.errors = (s.errors || 0) + 1;
s.lastMsgAt = Date.now();
flow.set('agg_only_stats', s);
flow.set('agg_only_isProcessing', false);

node.status({ fill: 'red', shape: 'ring', text: 'Error - unlocked' });
msg.payload = {
    ok: false,
    error: msg.error?.message || String(msg.error || 'Unknown error'),
    source: msg.error?.source || null,
    stats: s
};
return msg;

flow.set('agg_only_isProcessing', false);
flow.set('agg_only_data_all_buffer', []);
flow.set('agg_only_alarm_buffer', []);
node.status({ fill: 'green', shape: 'ring', text: 'Reset done' });
msg.payload = { ok: true, message: 'Aggregate only reset done' };
return msg;

// Debug / normalize ก่อนเข้า mongodb4 bulkWrite

let operations = msg.payload;

if (msg.payload?.operations) {
    operations = msg.payload.operations;
}

if (!Array.isArray(operations)) {
    node.error("bulkWrite operations is not array", msg);
    return null;
}

msg.collection = msg.collection || "data_all";
msg.operation = "bulkWrite";
msg.payload = [operations];
msg.options = msg.options || { ordered: false };

node.status({
    fill: "green",
    shape: "dot",
    text: `${msg.collection}: ${operations.length} ops`
});

return msg;

